import React, { useState } from 'react';

const ActionButton = ({ children, onClick, disabled = false }) => {
  return (
    <button
      className={`bg-cyan-500 hover:bg-cyan-700 text-white font-bold py-2 px-4 rounded ${
        disabled ? 'opacity-50 cursor-not-allowed' : ''
      }`}
      onClick={onClick}
      disabled={disabled}
    >
      {children}
    </button>
  );
};

const BalanceCard = ({ balance }) => {
  return (
    <div
      className="bg-gray-800 bg-opacity-50 backdrop-filter backdrop-blur-sm rounded-lg p-4 flex flex-col items-center"
    >
      <h2 className="text-2xl text-white font-bold mb-2" aria-label="Balance">
        Balance
      </h2>
      <p className="text-lg text-white font-bold" aria-label={`Balance: $${balance}`}>
        ${balance}
      </p>
    </div>
  );
};

const CryptoAsset = ({ name, price, amount, onChange, onClick, disabled = false }) => {
  return (
    <div
      className="bg-gray-800 bg-opacity-50 backdrop-filter backdrop-blur-sm rounded-lg p-4 flex justify-between items-center"
    >
      <div className="flex items-center">
        <svg
          xmlns="http://www.w3.org/2000/svg"
          className="h-6 w-6 text-purple-500"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
          strokeWidth={1.5}
        >
          <path
            strokeLinecap="round"
            strokeLinejoin="round"
            d="M17 14v6m-3-3h6M6 10h2a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v2a2 2 0 002 2m0-4h2a2 2 0 012 2v2m-4 4h2m-6-4h2m-6 4h2"
          />
        </svg>
        <p className="text-lg text-white font-bold ml-2" aria-label={name}>
          {name}
        </p>
      </div>
      <div className="flex items-center">
        <p className="text-lg text-white font-bold mr-2" aria-label={`Price: $${price}`}>
          ${price}
        </p>
        <input
          type="number"
          className="bg-gray-700 text-white font-bold py-2 px-4 rounded"
          value={amount}
          onChange={onChange}
          aria-label={`Amount of ${name}`}
        />
        <ActionButton onClick={onClick} disabled={disabled}>
          Buy/Sell
        </ActionButton>
      </div>
    </div>
  );
};

const CryptoAssetList = () => {
  const [assets, setAssets] = useState([
    { name: 'Bitcoin', price: 40000, amount: 0 },
    { name: 'Ethereum', price: 3000, amount: 0 },
    { name: 'Litecoin', price: 150, amount: 0 },
  ]);

  const handleAmountChange = (index, amount) => {
    setAssets(
      assets.map((asset, i) =>
        i === index ? { ...asset, amount: Number(amount) } : asset
      )
    );
  };

  const handleBuySell = (index) => {
    const asset = assets[index];
    if (asset.amount > 0) {
      console.log(`Buying/Selling ${asset.name} for $${asset.price * asset.amount}`);
    }
  };

  return (
    <div
      className="bg-gray-800 bg-opacity-50 backdrop-filter backdrop-blur-sm rounded-lg p-4"
    >
      <h2 className="text-2xl text-white font-bold mb-4" aria-label="Top Crypto Assets">
        Top Crypto Assets
      </h2>
      {assets.map((asset, index) => (
        <CryptoAsset
          key={index}
          name={asset.name}
          price={asset.price}
          amount={asset.amount}
          onChange={(e) => handleAmountChange(index, e.target.value)}
          onClick={() => handleBuySell(index)}
          disabled={asset.amount <= 0}
        />
      ))}
    </div>
  );
};

const Sidebar = () => {
  return (
    <div
      className="bg-gray-800 bg-opacity-50 backdrop-filter backdrop-blur-sm rounded-lg p-4 h-screen"
    >
      <h2 className="text-2xl text-white font-bold mb-4" aria-label="Menu">
        Menu
      </h2>
      <ul>
        <li className="text-lg text-white font-bold mb-2" aria-label="Dashboard">
          Dashboard
        </li>
        <li className="text-lg text-white font-bold mb-2" aria-label="Portfolio">
          Portfolio
        </li>
        <li className="text-lg text-white font-bold mb-2" aria-label="Settings">
          Settings
        </li>
      </ul>
    </div>
  );
};

const Dashboard = () => {
  return (
    <div className="flex h-screen bg-gray-900">
      <Sidebar />
      <div className="flex-1 p-4">
        <BalanceCard balance={10000} />
        <CryptoAssetList />
      </div>
    </div>
  );
};

export default Dashboard;

import React from 'react';

